import{_ as a,o as n,c as o,ae as t}from"./chunks/framework.DTQlDYOH.js";const l=JSON.parse('{"title":"Appendix: Engine and boardgame.io","description":"","frontmatter":{},"headers":[],"relativePath":"appendix/engine-and-bgio.md","filePath":"appendix/engine-and-bgio.md"}'),r={name:"appendix/engine-and-bgio.md"};function i(d,e,s,p,c,g){return n(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="appendix-engine-and-boardgame-io" tabindex="-1">Appendix: Engine and boardgame.io <a class="header-anchor" href="#appendix-engine-and-boardgame-io" aria-label="Permalink to &quot;Appendix: Engine and boardgame.io&quot;">​</a></h1><p>B.A.G.E.L. is interpreted by the <a href="https://www.npmjs.com/package/board-game-engine" target="_blank" rel="noreferrer">board-game-engine</a> npm package. The engine does not parse a custom text format; it takes a <strong>game definition object</strong> (the JSON you write) and:</p><ol><li><strong>Expands</strong> it (see <a href="/docs/reference/shorthand.html">Shorthand</a>, key renames, default entities and boards).</li><li><strong>Builds</strong> a <a href="https://boardgame.io/" target="_blank" rel="noreferrer">boardgame.io</a> game object: <code>setup</code>, <code>moves</code>, <code>turn</code>, <code>endIf</code>, optional <code>phases</code>, and <code>playerView</code> for hiding secret state.</li></ol><p>So your B.A.G.E.L. JSON is the configuration for the engine; the engine outputs a boardgame.io-compatible game that runs in the browser or on a server. The app uses <strong>board-game-engine-react</strong> to render boards and pieces and to connect to the game state.</p><h2 id="version" tabindex="-1">Version <a class="header-anchor" href="#version" aria-label="Permalink to &quot;Version&quot;">​</a></h2><p>The behavior described in these docs matches <strong>board-game-engine</strong> as used by this project (see root <code>package.json</code>). New engine versions may add move types, condition types, or options; the docs can be extended as the language grows.</p><h2 id="validation" tabindex="-1">Validation <a class="header-anchor" href="#validation" aria-label="Permalink to &quot;Validation&quot;">​</a></h2><p>There is no separate JSON Schema for B.A.G.E.L. yet. Invalid or unsupported structure is reported at runtime when the engine expands rules or when a move is executed.</p>',8)])])}const m=a(r,[["render",i]]);export{l as __pageData,m as default};
